/**
 * Standard Lenna test image (Wikimedia `Lenna_(test_image).png`), downscaled for embedding.
 * Used only by `/test-sixel` to probe DEC sixel support without network access.
 */
export const LENNA_TEST_PNG_BASE64 = `` as const;

export function lennaTestPngBuffer(): Buffer {
  return Buffer.from(LENNA_TEST_PNG_BASE64, "base64");
}
